DROP TABLE IF EXISTS `ra_bills`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `ra_bills` (
  `ra_bill_id` char(36) NOT NULL DEFAULT uuid(),
  `project_id` char(36) NOT NULL,
  `contract_id` char(36) NOT NULL,
  `ra_number` int(11) NOT NULL,
  `ra_code` varchar(50) DEFAULT NULL,
  `bill_period_from` date NOT NULL,
  `bill_period_to` date NOT NULL,
  `basic_amount_upto_date` decimal(18,2) DEFAULT 0.00,
  `basic_amount_upto_prev` decimal(18,2) DEFAULT 0.00,
  `basic_amount_this_bill` decimal(18,2) DEFAULT 0.00,
  `sgst_percent` decimal(5,2) DEFAULT 9.00,
  `cgst_percent` decimal(5,2) DEFAULT 9.00,
  `sgst_amount` decimal(18,2) DEFAULT 0.00,
  `cgst_amount` decimal(18,2) DEFAULT 0.00,
  `retention_percent` decimal(5,2) DEFAULT 5.00,
  `retention_amount` decimal(18,2) DEFAULT 0.00,
  `tds_percent` decimal(5,2) DEFAULT 2.00,
  `tds_amount` decimal(18,2) DEFAULT 0.00,
  `labour_cess_percent` decimal(5,2) DEFAULT 1.00,
  `labour_cess_amount` decimal(18,2) DEFAULT 0.00,
  `other_deductions` decimal(18,2) DEFAULT 0.00,
  `gross_amount` decimal(18,2) DEFAULT 0.00,
  `total_deductions` decimal(18,2) DEFAULT 0.00,
  `net_payable` decimal(18,2) DEFAULT 0.00,
  `stage` enum('draft','submitted','under_review','certified','paid','partially_paid') DEFAULT 'draft',
  `submitted_date` date DEFAULT NULL,
  `certified_date` date DEFAULT NULL,
  `certified_amount` decimal(18,2) DEFAULT 0.00,
  `payment_received` decimal(18,2) DEFAULT 0.00,
  `payment_date` date DEFAULT NULL,
  `rejection_amount` decimal(18,2) DEFAULT 0.00,
  `rejection_reason` text DEFAULT NULL,
  `prepared_by` varchar(150) DEFAULT NULL,
  `submitted_to` varchar(150) DEFAULT NULL,
  `ipc_number` int(11) DEFAULT NULL,
  `excel_file_name` varchar(300) DEFAULT NULL,
  `import_id` char(36) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`ra_bill_id`),
  UNIQUE KEY `uq_rabill` (`project_id`,`contract_id`,`ra_number`),
  KEY `fk_rabill_contract` (`contract_id`),
  KEY `idx_rabill_project` (`project_id`),
  KEY `idx_rabill_stage` (`stage`),
  CONSTRAINT `fk_rabill_contract` FOREIGN KEY (`contract_id`) REFERENCES `project_contracts` (`contract_id`),
  CONSTRAINT `fk_rabill_project` FOREIGN KEY (`project_id`) REFERENCES `projects` (`project_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

